// Limpia la respuesta del agente y agrega contexto del Telegram
const raw = $json.output ?? $json.text ?? '';

// Extraer el JSON aunque venga rodeado de texto
const match = String(raw).match(/\{[\s\S]*\}/);
let parsed = {};
try { parsed = JSON.parse(match ? match[0] : raw); } catch (e) { parsed = {}; }

const tg = $('Telegram Trigger').first().json.message;

return [{
  json: {
    tipo: parsed.tipo || 'gasto',
    monto: Number(parsed.monto) || 0,
    categoria: (parsed.categoria || 'otros').toLowerCase(),
    descripcion: parsed.descripcion || tg.text,
    usuario: tg.from?.username ? '@' + tg.from.username : tg.from?.first_name,
    raw_text: tg.text,
  }
}];
